mapper.insert:
INSERT INTO account_state (
  account_id,
  proxy_failure_count, pull_into_group_count,
  created_at, updated_at
) VALUES (
  #{accountId},
  #{proxyFailureCount}, #{pullIntoGroupCount},
  #{createdAt}, #{updatedAt}
)

mapper.select:
SELECT * FROM account_state
WHERE account_id = #{accountId}
LIMIT 1

mapper.update:
UPDATE account_state
SET login_state = #{loginState},
    last_state_sync_time = #{lastStateSyncTime},
    state_source = #{stateSource},
    updated_at = #{updatedAt}
WHERE account_id = #{accountId}

UPDATE account_state
SET account_state = #{row.accountState},
    last_state_sync_time = #{row.lastStateSyncTime},
    state_source = #{row.stateSource},
    updated_at = #{row.updatedAt}
WHERE account_id = #{row.accountId}
  AND account_state = #{unboundState}

UPDATE account_state
SET block_reason = #{blockReason},
    updated_at = #{updatedAt}
WHERE account_id = #{accountId}
